args.sparql:
SELECT ?player ?playerLabel (xsd:decimal(?runs) / (xsd:decimal(?innings) - xsd:decimal(?notouts)) AS ?average) WHERE {
  ?player wdt:P9315 ?runs ;
          wdt:P9301 ?innings ;
          wdt:P9302 ?notouts ;
          rdfs:label ?playerLabel .
  FILTER(LANG(?playerLabel) = "en") .
  FILTER(xsd:decimal(?innings) > xsd:decimal(?notouts)) .
}
ORDER BY DESC(?average)
LIMIT 1
